 33	    suggestions.length > 0 ||
 34	    msg.includes('max entries limit') ||
 35	    msg.includes('deadline exceeded') ||
 36	    msg.includes('maximum of series') ||
 37	    msg.includes('too many outstanding requests') ||
 38	    msg.includes('time range exceeds') ||
 39	    msg.includes('maximum resolution') ||
 40	    msg.includes('input size too long') ||
 41	    msg.includes('Network Error') ||
 42	    msg.includes('status code 401') ||
 43	    msg.includes('status code 403');
 44	
 45	  if (!hasSuggestions && !isLokiRelated) {
 46	    return null;
 47	  }
 48	
 49	  return (
 50	    <TextContent className={`error-suggestions ${compact ? 'error-suggestions-compact' : ''}`}>
