 56	
 57	      {suggestions.map((sugg, idx) => {
 58	        return (
 59	          <Text key={`suggestion_${idx}`} component={TextVariants.blockquote}>
 60	            {sugg}
 61	          </Text>
 62	        );
 63	      })}
 64	
 65	      {msg.includes('max entries limit') && (
 66	        <>
 67	          <Text component={TextVariants.blockquote}>
 68	            {t('Reduce the Query Options -> limit to reduce the number of results')}
 69	          </Text>
 70	          <Text component={TextVariants.blockquote}>
 71	            {t('Increase Loki "max_entries_limit_per_query" entry in configuration file')}
 72	          </Text>
 73	        </>
 74	      )}
 75	
 76	      {(msg.includes('deadline exceeded') ||
 77	        msg.includes('maximum of series') ||
 78	        msg.includes('too many outstanding requests')) && (
 79	        <>
 80	          <Text component={TextVariants.blockquote}>
 81	            {t('Add Namespace, Owner or Resource filters (which use indexed fields) to improve the query performance')}
 82	          </Text>
 83	          <Text component={TextVariants.blockquote}>
 84	            {t('Reduce limit and time range to decrease the number of results')}
 85	          </Text>
 86	          <Text component={TextVariants.blockquote}>
 87	            {t('Increase time step to decrease the number of parallel queries')}
 88	          </Text>
 89	          {msg.includes('too many outstanding requests') && (
 90	            <Text component={TextVariants.blockquote}>
 91	              {t(
 92	                'Ensure Loki config contains "parallelise_shardable_queries: true" and "max_outstanding_requests_per_tenant: 2048"'
 93	              )}
 94	            </Text>
 95	          )}
 96	        </>
 97	      )}
 98	
 99	      {(msg.includes('time range exceeds') || msg.includes('maximum resolution')) && (
100	        <>
101	          <Text component={TextVariants.blockquote}>
102	            {t('Reduce the time range to decrease the number of results')}
103	          </Text>
104	          <Text component={TextVariants.blockquote}>
105	            {t('Increase Loki "max_query_length" entry in configuration file')}
106	          </Text>
107	        </>
108	      )}
109	
110	      {msg.includes('input size too long') && (
111	        <>
112	          <Text component={TextVariants.blockquote}>
113	            {t('This error is generally seen when cluster admin groups are not properly configured.')}{' '}
114	            {t('Click the link below for more help.')}
115	          </Text>
116	          <Button
117	            variant="link"
118	            icon={<ExternalLinkSquareAltIcon />}
119	            iconPosition="right"
120	            component={(props: React.FunctionComponent) => (
