126	                  hash: 'loki-input-size-too-long-error'
127	                }}
128	              />
129	            )}
130	          >
131	            {t('More information')}
132	          </Button>
133	        </>
134	      )}
135	
136	      {msg.includes('Network Error') && (
137	        <Text component={TextVariants.blockquote}>
138	          {t(`Check your connectivity with cluster / console plugin pod`)}
139	        </Text>
140	      )}
141	
142	      {(msg.includes('status code 401') || msg.includes('status code 403')) && (
143	        <>
144	          <Text component={TextVariants.blockquote}>{t(`Check current user permissions`)}</Text>
145	          {msg.includes('user not an admin') ? (
146	            <Text component={TextVariants.blockquote}>
147	              {t(
148	                `This deployment mode does not support non-admin users. Check FlowCollector spec.loki.manual.authToken`
149	              )}
150	            </Text>
151	          ) : (
152	            <>
153	              {msg.includes('from Loki') && (
154	                <>
155	                  <Text component={TextVariants.blockquote}>
156	                    {t(`For LokiStack, your user must either:`)}
157	                    <TextList>
158	                      <TextListItem>
159	                        {t(`have the 'netobserv-loki-reader' cluster role, which allows multi-tenancy`)}
160	                      </TextListItem>
161	                      <TextListItem>
162	                        {t(`or be in the 'cluster-admin' group (not the same as the 'cluster-admin' role)`)}
163	                      </TextListItem>
164	                      <TextListItem>
165	                        {t(
166	                          `or LokiStack spec.tenants.openshift.adminGroups must be configured with a group this user belongs to`
167	                        )}
168	                      </TextListItem>
169	                    </TextList>
170	                  </Text>
171	                  <Text component={TextVariants.blockquote}>
172	                    {t(`For other configurations, refer to FlowCollector spec.loki.manual.authToken`)}
173	                  </Text>
174	                </>
175	              )}
176	            </>
177	          )}
178	          {msg.includes('from Prometheus') && (
179	            <Text component={TextVariants.blockquote}>
180	              {t(`For metrics access, your user must either:`)}
181	              <TextList>
182	                <TextListItem>{t(`have the 'netobserv-metrics-reader' namespace-scoped role`)}</TextListItem>
183	                <TextListItem>
184	                  {t(`or for cluster-wide access, have the 'cluster-monitoring-view' cluster role`)}
185	                </TextListItem>
186	              </TextList>
187	            </Text>
188	          )}
189	        </>
190	      )}
191	
192	      {isLokiRelated && (
193	        <div className="error-suggestions-links">
194	          <Button
195	            variant="link"
196	            icon={<ExternalLinkSquareAltIcon />}
197	            iconPosition="right"
198	            isInline
199	            component={(props: React.FunctionComponent) => (
200	              <Link
201	                {...props}
202	                target="_blank"
203	                to={{
204	                  pathname:
205	                    'https://docs.redhat.com/en/documentation/openshift_container_platform/latest/html/network_observability/installing-network-observability-operators',
206	                  hash: 'network-observability-loki-installation_network_observability'
207	                }}
208	              />
209	            )}
210	          >
211	            {t('Configuring the Loki Operator')}
212	          </Button>{' '}
213	          <Button
214	            variant="link"
215	            icon={<ExternalLinkSquareAltIcon />}
216	            iconPosition="right"
217	            isInline
218	            component={(props: React.FunctionComponent) => (
219	              <Link
220	                {...props}
221	                target="_blank"
222	                to={{ pathname: 'https://grafana.com/docs/loki/latest/configuration/' }}
223	              />
224	            )}
225	          >
226	            {t('Configuring Grafana Loki (community)')}
227	          </Button>
228	        </div>
229	      )}
230	    </TextContent>
231	  );
232	};
233	
234	export default ErrorSuggestions;

